import re

def checkAdminPassword(password):
    # Check for leading/trailing whitespace
    if password.strip() != password:
        return False
    # Check length between 12 and 128 characters
    if len(password) < 12 or len(password) > 128:
        return False
    # Check for uppercase, lowercase, digits, and special chars
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'\d', password):
        return False
    if not re.search(r'[!@#$%^&*(),.?":{}|<>]', password):
        return False
    # Check against common passwords (case-insensitive)
    common_passwords = {
        'password', '123456', '123456789', '12345678', '12345', '111111',
        '000000', 'admin', 'letmein', 'welcome', 'qwerty', 'abc123', 'iloveyou',
        'sunshine', 'password1', '1234567', 'login', 'admin123', '123123'
    }
    if password.lower() in common_passwords:
        return False
    return True

