        return None
    if hasattr(token, 'valid') and token.valid:
        return getattr(token, 'data', None)
    return None

import base64
import json


def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token.encode('utf-8'))
    except (base64.binascii.Error, UnicodeDecodeError):
        return None
    try:
        decoded_str = decoded.decode('utf-8')
        token = json.loads(decoded_str)
    except (UnicodeDecodeError, json.JSONDecodeError):
        return None
    if isinstance(token, dict) and token.get('valid', False):
        return token.get('data')
    return None

